def solve(nums, target):
    left, right = 0, len(nums) - 1
    while left < right:
        total = nums[left] + nums[right]
        if total == target:
            return left, right
        if total < target:
            left += 1
        else:
            right -= 1
    return -1, -1

# Additional checks for pitfalls
def check_indices(nums, left, right):
    if left == right or left < 0 or right >= len(nums):
        return False
    return True

def solve_with_checks(nums, target):
    left, right = 0, len(nums) - 1
    while left < right:
        total = nums[left] + nums[right]
        if total == target:
            if check_indices(nums, left, right):
                return left, right
        if total < target:
            left += 1
        else:
            right -= 1
    return -1, -1
